import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"西堂（西直门天主堂）","description":"","frontmatter":{},"headers":[],"relativePath":"religion/xitang.md","filePath":"religion/xitang.md","lastUpdated":null}'),n={name:"religion/xitang.md"};function d(i,t,s,o,h,g){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="西堂-西直门天主堂" tabindex="-1">西堂（西直门天主堂） <a class="header-anchor" href="#西堂-西直门天主堂" aria-label="Permalink to &quot;西堂（西直门天主堂）&quot;">​</a></h1><blockquote><p>&quot;老城区的静谧教堂，老北京风情的见证。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>西堂，又称西直门天主堂、圣母圣衣堂，位于北京市西城区西直门内大街130号，是北京四大天主教堂中规模最小的一座。教堂建于清雍正元年（1723年），采用意大利式建筑风格。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">6:00-20:00</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">免费</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">30分钟</td></tr><tr><td style="text-align:left;"><strong>弥撒时间</strong></td><td style="text-align:left;">周日6:30、8:00、10:00</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁2号线/4号线/13号线西直门站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市西城区西直门内大街130号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="始建" tabindex="-1">始建 <a class="header-anchor" href="#始建" aria-label="Permalink to &quot;始建&quot;">​</a></h3><p>西堂建于清雍正元年（1723年），由意大利籍传教士德里格神父创建。最初规模较小，后逐渐扩建。</p><h3 id="重建" tabindex="-1">重建 <a class="header-anchor" href="#重建" aria-label="Permalink to &quot;重建&quot;">​</a></h3><p>清嘉庆十六年（1811年），西堂因禁教政策被拆毁。同治六年（1867年），由孟振生主教重建，形成今日规模。</p><h3 id="近代" tabindex="-1">近代 <a class="header-anchor" href="#近代" aria-label="Permalink to &quot;近代&quot;">​</a></h3><p>1958年，西堂关闭。1994年，修复后重新开放，恢复宗教活动。</p><h2 id="建筑特色" tabindex="-1">建筑特色 <a class="header-anchor" href="#建筑特色" aria-label="Permalink to &quot;建筑特色&quot;">​</a></h2><h3 id="建筑风格" tabindex="-1">建筑风格 <a class="header-anchor" href="#建筑风格" aria-label="Permalink to &quot;建筑风格&quot;">​</a></h3><p>西堂采用意大利式建筑风格，与北京其他天主教堂风格不同：</p><ul><li><strong>规模较小</strong>：是四大堂中规模最小的</li><li><strong>意大利式</strong>：风格更接近意大利本土教堂</li><li><strong>钟楼</strong>：正面有一座钟楼</li><li><strong>立面简洁</strong>：立面设计简洁</li></ul><h3 id="外观" tabindex="-1">外观 <a class="header-anchor" href="#外观" aria-label="Permalink to &quot;外观&quot;">​</a></h3><p>西堂坐北朝南，正面朝向街道。</p><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>墙体</strong></td><td style="text-align:left;">青砖砌筑</td></tr><tr><td style="text-align:left;"><strong>屋顶</strong></td><td style="text-align:left;">中式大屋顶</td></tr><tr><td style="text-align:left;"><strong>钟楼</strong></td><td style="text-align:left;">正面有一座钟楼</td></tr><tr><td style="text-align:left;"><strong>高度</strong></td><td style="text-align:left;">钟楼高约15米</td></tr></tbody></table><h3 id="内部" tabindex="-1">内部 <a class="header-anchor" href="#内部" aria-label="Permalink to &quot;内部&quot;">​</a></h3><p>西堂内部空间较小，但精致典雅。</p><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>面积</strong></td><td style="text-align:left;">约300平方米</td></tr><tr><td style="text-align:left;"><strong>容量</strong></td><td style="text-align:left;">可容纳300余人</td></tr><tr><td style="text-align:left;"><strong>祭台</strong></td><td style="text-align:left;">主祭台供奉圣母像</td></tr><tr><td style="text-align:left;"><strong>装饰</strong></td><td style="text-align:left;">内部装饰精美</td></tr></tbody></table><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>教堂参观（约30分钟）</strong>：</p><p>西直门地铁站 → 步行至教堂 → 内部参观 → 外部拍照</p><p><strong>结合西直门路线</strong>：</p><p>西直门商圈 → 西堂参观 → 凯德MALL购物</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">站点</th></tr></thead><tbody><tr><td style="text-align:left;">地铁</td><td style="text-align:left;">2号线/4号线/13号线西直门站</td></tr><tr><td style="text-align:left;">公交</td><td style="text-align:left;">7路、105路、111路等西直门内站</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>规模较小</strong>：四大堂中规模最小的</li><li><strong>老城区风情</strong>：周围是老北京城区，可体验老北京生活</li><li><strong>安静祥和</strong>：游客较少，安静祥和</li><li><strong>弥撒时间</strong>：注意弥撒时间</li><li><strong>结合购物</strong>：可与西直门商圈结合</li></ol><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">西直门商圈</td><td style="text-align:center;">紧邻</td><td style="text-align:left;">大型购物中心</td></tr><tr><td style="text-align:left;">凯德MALL</td><td style="text-align:center;">步行5分钟</td><td style="text-align:left;">大型商场</td></tr><tr><td style="text-align:left;">北京北站</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">火车站</td></tr><tr><td style="text-align:left;">什刹海</td><td style="text-align:center;">步行20分钟</td><td style="text-align:left;">老北京风情</td></tr><tr><td style="text-align:left;">北海公园</td><td style="text-align:center;">步行25分钟</td><td style="text-align:left;">皇家园林</td></tr></tbody></table><h2 id="文化价值" tabindex="-1">文化价值 <a class="header-anchor" href="#文化价值" aria-label="Permalink to &quot;文化价值&quot;">​</a></h2><p>西堂是北京四大天主教堂之一，虽然规模较小，但历史悠久，是中西文化交流的见证。</p><p>西堂位于老北京城区，周围是北京传统民居，可以体验老北京的生活气息。</p><hr><p><strong>📍 地址</strong>：北京市西城区西直门内大街130号</p>',40)])])}const y=e(n,[["render",d]]);export{f as __pageData,y as default};
